TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_PROFESIONALES_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_PROFESIONALES_ENTIDAD (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_TIPO_IDENTIFICACION, IDENTIFICACION,
            NOMBRE, APELLIDO, CORREO, TELEFONO, ID_ESPECIALIDAD,
            OTRA_ESPECIALIDAD, FECHA_CREACION
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION,
            :NEW.NOMBRE, :NEW.APELLIDO, :NEW.CORREO, :NEW.TELEFONO, :NEW.ID_ESPECIALIDAD,
            :NEW.OTRA_ESPECIALIDAD, :NEW.FECHA_CREACION
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_PROFESIONALES_ENTIDAD (
                ENVIO_BQ, ID, ID_ENTIDAD, ID_TIPO_IDENTIFICACION, IDENTIFICACION,
                NOMBRE, APELLIDO, CORREO, TELEFONO, ID_ESPECIALIDAD,
                OTRA_ESPECIALIDAD, FECHA_CREACION
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_TIPO_IDENTIFICACION, :NEW.IDENTIFICACION,
                :NEW.NOMBRE, :NEW.APELLIDO, :NEW.CORREO, :NEW.TELEFONO, :NEW.ID_ESPECIALIDAD,
                :NEW.OTRA_ESPECIALIDAD, :NEW.FECHA_CREACION
            );       

       ELSE

            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_PROFESIONALES_ENTIDAD
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                ID_ENTIDAD = :NEW.ID_ENTIDAD,
                ID_TIPO_IDENTIFICACION = :NEW.ID_TIPO_IDENTIFICACION,
                IDENTIFICACION = :NEW.IDENTIFICACION,
                NOMBRE = :NEW.NOMBRE,
                APELLIDO = :NEW.APELLIDO,
                CORREO = :NEW.CORREO,
                TELEFONO = :NEW.TELEFONO,
                ID_ESPECIALIDAD = :NEW.ID_ESPECIALIDAD,
                OTRA_ESPECIALIDAD = :NEW.OTRA_ESPECIALIDAD,
                FECHA_CREACION = :NEW.FECHA_CREACION
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
      END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN

       SELECT (SELECT ENVIO_BQ FROM TKRBQ_PROFESIONALES_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_PROFESIONALES_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;        

        INSERT INTO TKRBQ_PROFESIONALES_ENTIDAD (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_TIPO_IDENTIFICACION, IDENTIFICACION,
            NOMBRE, APELLIDO, CORREO, TELEFONO, ID_ESPECIALIDAD,
            OTRA_ESPECIALIDAD, FECHA_CREACION
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.ID_ENTIDAD, :OLD.ID_TIPO_IDENTIFICACION, :OLD.IDENTIFICACION,
            :OLD.NOMBRE, :OLD.APELLIDO, :OLD.CORREO, :OLD.TELEFONO, :OLD.ID_ESPECIALIDAD,
            :OLD.OTRA_ESPECIALIDAD, :OLD.FECHA_CREACION
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_PROFESIONALES_ENTIDAD';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
